// --- Golden invariant: cosmetic-variant dedup (interview Q1, Q10) -----

// from interview: Q1, Q10
func TestCreateBookmark_CosmeticVariants_AllDedupToSameExisting(t *testing.T) {
	repo, _, _ := newTestRepository(t)
	ctx := context.Background()

	original, err := repo.Create(ctx, domain.NewBookmark{OriginalURL: "https://example.com/x"})
	require.NoError(t, err)

	variants := []struct {
		name string
		url  string
	}{
		{"http scheme", "http://example.com/x"},
		{"www prefix", "https://www.example.com/x"},
		{"trailing slash", "https://example.com/x/"},
		{"utm_source tracking param", "https://example.com/x?utm_source=foo"},
		{"gclid tracking param", "https://example.com/x?gclid=abc123"},
		{"fbclid tracking param", "https://example.com/x?fbclid=xyz"},
	}

	for _, v := range variants {
		t.Run(v.name, func(t *testing.T) {
			_, err := repo.Create(ctx, domain.NewBookmark{OriginalURL: v.url})
			require.Error(t, err)
			var repoErr *adapter.RepositoryError
			require.True(t, errors.As(err, &repoErr))
			assert.Equal(t, adapter.ErrKindDuplicate, repoErr.Kind)
			require.NotNil(t, repoErr.Existing)
			assert.Equal(t, original.ID, repoErr.Existing.ID, "variant %q must dedup to the original bookmark", v.url)
		})
	}

	board, err := repo.Board(ctx, adapter.BoardFilter{})
	require.NoError(t, err)
	assert.Len(t, board.Inbox, 1, "exactly one entry should exist for this link after all variant attempts")
}

