func TestCreateBookmark_QueryParamAsymmetry_TrackingStrippedMeaningfulKept(t *testing.T) {
	repo, _, _ := newTestRepository(t)
	ctx := context.Background()

	// Tracking params are stripped by the locked deny-list rule.
	_, err := repo.Create(ctx, domain.NewBookmark{OriginalURL: "https://example.com/a"})
	require.NoError(t, err)
	_, err = repo.Create(ctx, domain.NewBookmark{OriginalURL: "https://example.com/a?utm_source=x"})
	require.Error(t, err, "utm_source is a tracking param and must be stripped, deduping with the bare URL")

	// Meaningful params are preserved — genuinely distinct bookmarks.
	_, err = repo.Create(ctx, domain.NewBookmark{OriginalURL: "https://example.com/b?page=2"})
	require.NoError(t, err)
	_, err = repo.Create(ctx, domain.NewBookmark{OriginalURL: "https://example.com/b?page=3"})
	require.NoError(t, err, "page=2 and page=3 are meaningfully different bookmarks, not a duplicate")
}

