// from interview: Q3, Q5
func TestBoard_PositionOrderingByteOrder_RegardlessOfServerLocale(t *testing.T) {
	repo, pool, _ := newTestRepository(t)
	ctx := context.Background()

	var collation *string
	err := pool.QueryRow(ctx,
		`SELECT collation_name FROM information_schema.columns WHERE table_name = 'bookmarks' AND column_name = 'position'`,
	).Scan(&collation)
	require.NoError(t, err)
	require.NotNil(t, collation, "position column must have an explicit collation")
	assert.Equal(t, "C", *collation, `position column must be COLLATE "C" for byte-order guarantees`)

	_, err = repo.Create(ctx, domain.NewBookmark{OriginalURL: "https://example.com/1"})
	require.NoError(t, err)
	_, err = repo.Create(ctx, domain.NewBookmark{OriginalURL: "https://example.com/2"})
	require.NoError(t, err)

	board, err := repo.Board(ctx, adapter.BoardFilter{})
	require.NoError(t, err)
	require.Len(t, board.Inbox, 2)
	assert.LessOrEqual(t, string(board.Inbox[0].Position), string(board.Inbox[1].Position), "Board must return byte-order position ordering")
}

