// --- Concurrency (interview Q8) ---------------------------------------

// from interview: Q8
func TestCreateBookmark_ConcurrentDifferentURLs_StableOrderByPositionThenID(t *testing.T) {
	repo, _, _ := newTestRepository(t)
	ctx := context.Background()

	const n = 10
	var wg sync.WaitGroup
	errs := make([]error, n)
	for i := 0; i < n; i++ {
		wg.Add(1)
		go func(i int) {
			defer wg.Done()
			_, err := repo.Create(ctx, domain.NewBookmark{OriginalURL: fmt.Sprintf("https://example.com/concurrent-%d", i)})
			errs[i] = err
		}(i)
	}
	wg.Wait()

	for i, err := range errs {
		assert.NoError(t, err, "concurrent Create %d should succeed — different URLs, no dedup conflict", i)
	}

	board1, err := repo.Board(ctx, adapter.BoardFilter{})
	require.NoError(t, err)
	board2, err := repo.Board(ctx, adapter.BoardFilter{})
	require.NoError(t, err)
	require.Len(t, board1.Inbox, n)
	require.Len(t, board2.Inbox, n)
	for i := range board1.Inbox {
		assert.Equal(t, board1.Inbox[i].ID, board2.Inbox[i].ID, "Board order must be stable across repeated calls given position ties")
	}
}

