// from interview: Q2
func TestCreateBookmark_ContextCanceledMidQuery_WrappedInfraError_NoPartialWrite(t *testing.T) {
	repo, pool, _ := newTestRepository(t)
	ctx, cancel := context.WithTimeout(context.Background(), 1*time.Millisecond)
	defer cancel()
	time.Sleep(5 * time.Millisecond)

	_, err := repo.Create(ctx, domain.NewBookmark{OriginalURL: "https://example.com/a"})
	require.Error(t, err)

	var repoErr *adapter.RepositoryError
	assert.False(t, errors.As(err, &repoErr), "a context deadline must surface as a plain wrapped infra error, never a *RepositoryError with a domain Kind")

	var count int
	require.NoError(t, pool.QueryRow(context.Background(), "SELECT count(*) FROM bookmarks").Scan(&count))
	assert.Zero(t, count, "no partial row should be written when the context deadline is exceeded")
}

// from interview: Q2
func TestCreateBookmark_PoolAcquireTimeout_WrappedInfraError(t *testing.T) {
	dsn := testDSN(t)
	ctx := context.Background()

	cfg, err := pgxpool.ParseConfig(dsn)
	require.NoError(t, err)
	cfg.MaxConns = 1
	pool, err := pgxpool.NewWithConfig(ctx, cfg)
	require.NoError(t, err)
	defer pool.Close()

	held, err := pool.Acquire(ctx)
	require.NoError(t, err)
	defer held.Release()

	repo := postgres.New(pool, fixedClock(time.Now().UTC()))
	acquireCtx, cancel := context.WithTimeout(ctx, 200*time.Millisecond)
	defer cancel()

	_, err = repo.Create(acquireCtx, domain.NewBookmark{OriginalURL: "https://example.com/a"})
	require.Error(t, err, "Create must fail when the pool cannot acquire a connection before the context deadline")

	var repoErr *adapter.RepositoryError
	assert.False(t, errors.As(err, &repoErr), "pool acquire timeout is an infrastructure failure, never a domain ErrorKind")
}

