// TestIsDuplicateConstraintViolation_OtherConstraint_False: gen_random_uuid()
// makes a real bookmarks_pkey collision un-inducible through the public
// Create API, so this forces one via a raw duplicate-id insert.
// from interview: Q2, Q6
func TestIsDuplicateConstraintViolation_OtherConstraint_False(t *testing.T) {
	_, pool, _ := newTestRepository(t)
	ctx := context.Background()

	const sharedID = "11111111-1111-1111-1111-111111111111"
	require.NoError(t, insertRawBookmark(ctx, pool, sharedID, "hash-one"))

	err := insertRawBookmark(ctx, pool, sharedID, "hash-two")
	require.Error(t, err, "inserting a second row with the same id must violate bookmarks_pkey")

	assert.False(t, postgres.IsDuplicateConstraintViolation(err), "a bookmarks_pkey violation must NOT be classified as a duplicate-URL (bookmarks_identity_hash_idx) violation")
}
